local p = {}
function p.main() local title = mw.title.getCurrentTitle() local prefix, brackets = mw.ustring.match(title.text, '(.+) (%([^%(%)]+%))$') local result if prefix and brackets then result = "''" .. prefix .. "'' " .. brackets else result = "''" .. title.text .. "''" end result = '{{DISPLAYTITLE:' .. title.nsText .. result .. '}}' return mw.getCurrentFrame:preprocess(result) end
return p

local p = {}
function p.main() local title = mw.title.getCurrentTitle() local prefix, brackets = mw.ustring.match(title.text, '(.+) (%([^%(%)]+%))$') local result if prefix and brackets then result = "''" .. prefix .. "'' " .. brackets else result = "''" .. title.text .. "''" end return mw.getCurrentFrame():callParserFunction( 'DISPLAYTITLE', title.nsText .. result ) end
return p

local p = {}
function p.main() local title = mw.title.getCurrentTitle() local prefix, brackets = mw.ustring.match(title.text, '(.+) (%([^%(%)]+%))$') local result if prefix and brackets then result = "''" .. prefix .. "'' " .. brackets else result = "''" .. title.text .. "''" end return result end
return p

local p = {}
function p.main() local title = mw.title.getCurrentTitle() local prefix, brackets = mw.ustring.match(title.text, '(.+) (%([^%(%)]+%))$') local result if prefix and brackets then result = "''" .. prefix .. "'' " .. brackets else result = "''" .. title.text .. "''" end return title.nsText .. result end
return p

local p = {}
function p.main() local title = mw.title.getCurrentTitle() local prefix, brackets = mw.ustring.match(title.text, '(.+) (%([^%(%)]+%))$') local result if prefix and brackets then result = "''" .. prefix .. "'' " .. brackets else result = "''" .. title.text .. "''" end if title.nsText and title.nsText ~= "" then result = title.nsText .. ':' .. result end return mw.getCurrentFrame():callParserFunction( 'DISPLAYTITLE', result ) end
return p

-- This module implements {{italic title}}.

local p = {}

function p._main(args, frame, title)
	args = args or {}
	frame = frame or mw.getCurrentFrame()
	title = title or mw.title.getCurrentTitle()
	local prefix, parentheses = mw.ustring.match(title.text, '^(.+) (%([^%(%)]+%))$')
	local result
	if prefix and parentheses and args.all ~= 'yes' then
		result = string.format("''%s'' %s", prefix, parentheses)
	else
		result = string.format("''%s''", title.text)
	end
	if title.namespace ~= 0 then
		result = title.nsText .. ':' .. result
	end
	return frame:callParserFunction('DISPLAYTITLE', result, args[1])
end

function p.main(frame)
	local args = require('Module:Arguments').getArgs(frame, {
		wrappers = 'Template:Italic title'
	})
	return p._main(args, frame)
end

return p

